{
  "mode": "method",
  "tests": [
    {
      "name": "default_schema_fallback",
      "input": {},
      "output": "public",
      "notes": "Tests if the application defaults to 'public' schema when POSTGRES_SCHEMA is not set."
    },
    {
      "name": "custom_schema_configuration",
      "input": { "POSTGRES_SCHEMA": "custom_schema" },
      "output": "custom_schema",
      "notes": "Validates that the application correctly uses the custom schema provided in the environment variable."
    },
    {
      "name": "connection_string_without_schema",
      "input": { "DATABASE_URL": "postgresql://user:password@localhost:5432/mydb" },
      "output": "mydb",
      "notes": "Ensures the application can connect to the database without a schema in the connection string."
    },
    {
      "name": "migration_with_custom_schema",
      "input": { "POSTGRES_SCHEMA": "migration_schema" },
      "output": "migrations applied to migration_schema",
      "notes": "Tests if migrations run correctly on the configured custom schema."
    },
    {
      "name": "migration_without_schema",
      "input": {},
      "output": "migrations applied to public",
      "notes": "Validates that migrations run on the default 'public' schema when no custom schema is set."
    },
    {
      "name": "invalid_schema_name",
      "input": { "POSTGRES_SCHEMA": "invalid/schema" },
      "output": "error",
      "notes": "Tests how the application handles an invalid schema name format."
    },
    {
      "name": "schema_documentation_update",
      "input": {},
      "output": "README.md updated with schema instructions",
      "notes": "Ensures that the README.md is updated to reflect schema configuration options."
    },
    {
      "name": "environment_variable_documentation",
      "input": {},
      "output": "env.sample updated with POSTGRES_SCHEMA",
      "notes": "Validates that .env.sample includes documentation for the POSTGRES_SCHEMA variable."
    }
  ],
  "assumptions": "The application is expected to read environment variables correctly and handle migrations as per the configured schema.",
  "notes": "Tests should cover both successful configurations and edge cases to ensure robustness."
}
